/**
 * Dispatch a notification event on the EventBus.
 * Channel handlers subscribed to `notification:requested` will pick it up.
 */
dispatchNotification(params: {
  channel: string;
  recipient: string;
  subject: string;
  body: string;
}): void {
  const event: NotificationRequestedEvent = {
    type: 'notification:requested',
    channel: params.channel,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    timestamp: new Date(),
  };
  // Synchronous emit — handlers run inline since EventBus.emit is async
  // but our handlers are synchronous
  void this.eventBus.emit(event);
}

